async function seed() {
  const connection = await mysql.createConnection(process.env.DATABASE_URL);
  console.log("🌟 Iniciando seed de tarotistas...");

  for (const t of tarotistasData) {
    await connection.execute(
      `INSERT INTO tarotistas (name, slug, tagline, bio, specialty, specialties, experience, rating, reviewCount, pricePerSession, available, featured, arcana, style, languages, responseTime, totalConsultations, systemPrompt)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
       ON DUPLICATE KEY UPDATE name=VALUES(name), tagline=VALUES(tagline)`,
      [t.name, t.slug, t.tagline, t.bio, t.specialty, t.specialties, t.experience, t.rating, t.reviewCount, t.pricePerSession, t.available ? 1 : 0, t.featured ? 1 : 0, t.arcana, t.style, t.languages, t.responseTime, t.totalConsultations, t.systemPrompt]
    );
  }

  for (const b of bonosData) {
    await connection.execute(
      `INSERT INTO bonos (name, description, sessions, price, originalPrice, validDays, active, featured)
       VALUES (?, ?, ?, ?, ?, ?, ?, ?)
       ON DUPLICATE KEY UPDATE name=VALUES(name)`,
      [b.name, b.description, b.sessions, b.price, b.originalPrice, b.validDays, b.active ? 1 : 0, b.featured ? 1 : 0]
    );
  }

  console.log(`✅ ${tarotistasData.length} tarotistas insertadas correctamente`);
  console.log(`✅ ${bonosData.length} bonos insertados correctamente`);
  await connection.end();
}

seed().catch(console.error);
